"use client";

import Link from "next/link";
import Image from "next/image";
import { useEffect, useState } from "react";

import type { NavItem } from "@/lib/site-content";

type SiteHeaderProps = {
  items: NavItem[];
  primaryHref: string;
  primaryLabel: string;
};

export function SiteHeader({
  items,
  primaryHref,
  primaryLabel,
}: SiteHeaderProps) {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 24);
    };

    handleScroll();
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <header className={`siteHeader ${scrolled ? "siteHeaderScrolled" : ""}`}>
      <div className="container siteHeaderInner">
        <Link href="/" className="brandLink" aria-label="OpenCrab 首页">
          <Image
            src="/branding/opencrab-logo.svg"
            alt="OpenCrab"
            width={164}
            height={55}
            priority
          />
        </Link>

        <nav className="siteNav" aria-label="主导航">
          {items.map((item) =>
            item.external ? (
              <a
                key={item.href}
                href={item.href}
                className="siteNavLink"
                target="_blank"
                rel="noreferrer"
              >
                {item.label}
              </a>
            ) : (
              <Link key={item.href} href={item.href} className="siteNavLink">
                {item.label}
              </Link>
            ),
          )}
        </nav>

        <div className="siteHeaderActions">
          <Link href={primaryHref} className="button buttonPrimary headerButton">
            {primaryLabel}
          </Link>
        </div>
      </div>
    </header>
  );
}
